const questions=[{category:"HTML",question:"Balise pour inserer une video ?",options:["<code>&lt;media&gt;</code>","<code>&lt;video&gt;</code>","<code>&lt;movie&gt;</code>","<code>&lt;vid&gt;</code>"],answer:1,explanation:"<code>&lt;video&gt;</code> = balise HTML5 standard."},{category:"HTML",question:"Balise pour un fichier audio ?",options:["<code>&lt;sound&gt;</code>","<code>&lt;audio&gt;</code>","<code>&lt;music&gt;</code>","<code>&lt;mp3&gt;</code>"],answer:1,explanation:"<code>&lt;audio&gt;</code> integre des fichiers audio."},{category:"HTML",question:"Balise pour une section ?",options:["<code>&lt;div&gt;</code>","<code>&lt;section&gt;</code>","<code>&lt;block&gt;</code>","<code>&lt;area&gt;</code>"],answer:1,explanation:"<code>&lt;section&gt;</code> = balise semantique."},{category:"HTML",question:"Balise en-tete de page ?",options:["<code>&lt;top&gt;</code>","<code>&lt;header&gt;</code>","<code>&lt;head&gt;</code>","<code>&lt;title&gt;</code>"],answer:1,explanation:"<code>&lt;header&gt;</code> = en-tete semantique."},{category:"HTML",question:"Balise pied de page ?",options:["<code>&lt;bottom&gt;</code>","<code>&lt;footer&gt;</code>","<code>&lt;end&gt;</code>","<code>&lt;foot&gt;</code>"],answer:1,explanation:"<code>&lt;footer&gt;</code> = pied de page."},{category:"HTML",question:"Zone de navigation ?",options:["<code>&lt;menu&gt;</code>","<code>&lt;nav&gt;</code>","<code>&lt;navigate&gt;</code>","<code>&lt;links&gt;</code>"],answer:1,explanation:"<code>&lt;nav&gt;</code> = navigation."},{category:"HTML",question:"Ligne horizontale ?",options:["<code>&lt;line&gt;</code>","<code>&lt;hr&gt;</code>","<code>&lt;br&gt;</code>","<code>&lt;hl&gt;</code>"],answer:1,explanation:"<code>&lt;hr&gt;</code> = horizontal rule."},{category:"HTML",question:"Saut de ligne ?",options:["<code>&lt;lb&gt;</code>","<code>&lt;br&gt;</code>","<code>&lt;break&gt;</code>","<code>&lt;nl&gt;</code>"],answer:1,explanation:"<code>&lt;br&gt;</code> = break."},{category:"CSS",question:"Propriete pour la position ?",options:["<code>place</code>","<code>position</code>","<code>align</code>","<code>float</code>"],answer:1,explanation:"<code>position</code> : static, relative, absolute, fixed, sticky."},{category:"CSS",question:"Valeur par defaut de position ?",options:["<code>relative</code>","<code>absolute</code>","<code>static</code>","<code>fixed</code>"],answer:2,explanation:"<code>static</code> = valeur par defaut."},{category:"CSS",question:"Propriete de superposition ?",options:["<code>index</code>","<code>z-index</code>","<code>layer</code>","<code>stack</code>"],answer:1,explanation:"<code>z-index</code> controle l'empilement."},{category:"CSS",question:"Controle du debordement ?",options:["<code>overflow</code>","<code>flow</code>","<code>scroll</code>","<code>wrap</code>"],answer:0,explanation:"<code>overflow</code> gere le contenu debordant."},{category:"CSS",question:"Cacher le debordement ?",options:["<code>hidden</code>","<code>none</code>","<code>off</code>","<code>invisible</code>"],answer:0,explanation:"<code>overflow: hidden</code> cache le debordement."},{category:"CSS",question:"Texte en majuscules ?",options:["<code>text-style</code>","<code>text-transform</code>","<code>font-case</code>","<code>uppercase</code>"],answer:1,explanation:"<code>text-transform: uppercase</code>."},{category:"CSS",question:"Ombre au texte ?",options:["<code>text-shadow</code>","<code>font-shadow</code>","<code>shadow-text</code>","<code>text-effect</code>"],answer:0,explanation:"<code>text-shadow</code> ajoute une ombre."},{category:"CSS",question:"Changer le curseur ?",options:["<code>pointer</code>","<code>mouse</code>","<code>cursor</code>","<code>select</code>"],answer:2,explanation:"<code>cursor</code> definit l'apparence."},{category:"JavaScript",question:"Arreter une boucle ?",options:["<code>stop</code>","<code>break</code>","<code>exit</code>","<code>end</code>"],answer:1,explanation:"<code>break</code> interrompt la boucle."},{category:"JavaScript",question:"Iteration suivante ?",options:["<code>skip</code>","<code>continue</code>","<code>next</code>","<code>pass</code>"],answer:1,explanation:"<code>continue</code> passe a l'iteration suivante."},{category:"JavaScript",question:"Type vrai/faux ?",options:["<code>bool</code>","<code>boolean</code>","<code>logic</code>","<code>binary</code>"],answer:1,explanation:"<code>boolean</code> pour true/false."},{category:"JavaScript",question:"Boite de dialogue ?",options:["<code>prompt()</code>","<code>alert()</code>","<code>confirm()</code>","<code>dialog()</code>"],answer:1,explanation:"<code>alert()</code> affiche un message."},{category:"JavaScript",question:"Saisie utilisateur ?",options:["<code>input()</code>","<code>prompt()</code>","<code>ask()</code>","<code>get()</code>"],answer:1,explanation:"<code>prompt()</code> demande une saisie."},{category:"JavaScript",question:"Confirmer une action ?",options:["<code>confirm()</code>","<code>validate()</code>","<code>check()</code>","<code>verify()</code>"],answer:0,explanation:"<code>confirm()</code> retourne true/false."},{category:"JavaScript",question:"Gerer les erreurs ?",options:["<code>catch</code>","<code>try</code>","<code>error</code>","<code>exception</code>"],answer:1,explanation:"<code>try</code> entoure le code a risque."},{category:"JavaScript",question:"Capturer une erreur ?",options:["<code>catch</code>","<code>grab</code>","<code>take</code>","<code>handle</code>"],answer:0,explanation:"<code>catch</code> capture l'erreur du try."},{category:"PHP",question:"Supprimer les espaces ?",options:["<code>strip()</code>","<code>trim()</code>","<code>clean()</code>","<code>remove()</code>"],answer:1,explanation:"<code>trim()</code> supprime les espaces."},{category:"PHP",question:"Convertir en minuscules ?",options:["<code>lower()</code>","<code>strtolower()</code>","<code>small()</code>","<code>min()</code>"],answer:1,explanation:"<code>strtolower()</code> convertit en minuscules."},{category:"PHP",question:"Variable existe ?",options:["<code>isset()</code>","<code>exist()</code>","<code>check()</code>","<code>defined()</code>"],answer:0,explanation:"<code>isset()</code> verifie l'existence."},{category:"PHP",question:"Detruire une variable ?",options:["<code>remove()</code>","<code>unset()</code>","<code>delete()</code>","<code>clear()</code>"],answer:1,explanation:"<code>unset()</code> detruit la variable."},{category:"PHP",question:"Demarrer une session ?",options:["<code>session_start()</code>","<code>start_session()</code>","<code>session_open()</code>","<code>begin_session()</code>"],answer:0,explanation:"<code>session_start()</code> demarre la session."},{category:"PHP",question:"Variable des sessions ?",options:["<code>$_SESSION</code>","<code>$_COOKIE</code>","<code>$_SERVER</code>","<code>$_GLOBAL</code>"],answer:0,explanation:"<code>$_SESSION</code> stocke les sessions."},{category:"MySQL",question:"Renommer une table ?",options:["<code>RENAME TABLE</code>","<code>CHANGE TABLE</code>","<code>MODIFY TABLE</code>","<code>UPDATE TABLE</code>"],answer:0,explanation:"<code>RENAME TABLE ancien TO nouveau;</code>"},{category:"MySQL",question:"Ajouter une colonne ?",options:["<code>ADD COLUMN</code>","<code>INSERT COLUMN</code>","<code>CREATE COLUMN</code>","<code>NEW COLUMN</code>"],answer:0,explanation:"<code>ALTER TABLE ADD COLUMN...</code>"},{category:"MySQL",question:"Supprimer une colonne ?",options:["<code>DELETE COLUMN</code>","<code>DROP COLUMN</code>","<code>REMOVE COLUMN</code>","<code>ERASE COLUMN</code>"],answer:1,explanation:"<code>ALTER TABLE DROP COLUMN...</code>"},{category:"MySQL",question:"Modifier une table ?",options:["<code>CHANGE TABLE</code>","<code>MODIFY TABLE</code>","<code>ALTER TABLE</code>","<code>UPDATE TABLE</code>"],answer:2,explanation:"<code>ALTER TABLE</code> modifie la structure."},{category:"MySQL",question:"Compter les lignes ?",options:["<code>TOTAL()</code>","<code>COUNT()</code>","<code>SUM()</code>","<code>NUMBER()</code>"],answer:1,explanation:"<code>COUNT()</code> compte les lignes."},{category:"MySQL",question:"Calculer la somme ?",options:["<code>ADD()</code>","<code>SUM()</code>","<code>TOTAL()</code>","<code>PLUS()</code>"],answer:1,explanation:"<code>SUM()</code> somme une colonne."},{category:"MySQL",question:"Valeur maximale ?",options:["<code>MAX()</code>","<code>TOP()</code>","<code>HIGH()</code>","<code>BIG()</code>"],answer:0,explanation:"<code>MAX()</code> retourne le maximum."},{category:"MySQL",question:"Valeur minimale ?",options:["<code>MIN()</code>","<code>LOW()</code>","<code>SMALL()</code>","<code>LESS()</code>"],answer:0,explanation:"<code>MIN()</code> retourne le minimum."},{category:"MySQL",question:"Joindre deux tables ?",options:["<code>LINK</code>","<code>JOIN</code>","<code>CONNECT</code>","<code>MERGE</code>"],answer:1,explanation:"<code>JOIN</code> combine les lignes."},{category:"MySQL",question:"Valeurs distinctes ?",options:["<code>UNIQUE</code>","<code>DISTINCT</code>","<code>SINGLE</code>","<code>ONLY</code>"],answer:1,explanation:"<code>SELECT DISTINCT</code> elimine les doublons."}];
let currentQuestion=0,score=0,selectedOption=-1,answered=false,shuffledQuestions=[],answers=[],timerInterval=null,timerSeconds=0;function startTimer(){timerSeconds=0;clearInterval(timerInterval);timerInterval=setInterval(()=>{timerSeconds++;document.getElementById('timer').textContent=String(Math.floor(timerSeconds/60)).padStart(2,'0')+':'+String(timerSeconds%60).padStart(2,'0');},1000);}function stopTimer(){clearInterval(timerInterval);}function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}function startQuiz(){shuffledQuestions=shuffle(questions);currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}function showQuestion(){selectedOption=-1;answered=false;const q=shuffledQuestions[currentQuestion],t=shuffledQuestions.length;document.getElementById('progress-text').textContent=`Question ${currentQuestion+1} / ${t}`;document.getElementById('progress-fill').style.width=((currentQuestion+1)/t*100)+'%';document.getElementById('btn-validate').style.display='inline-block';document.getElementById('btn-validate').disabled=true;document.getElementById('btn-next').style.display='none';let h=`<span class="category-badge cat-${q.category.toLowerCase()}">${q.category}</span><div class="question-text">${q.question}</div><ul class="options">`;q.options.forEach((o,i)=>{h+=`<li onclick="selectOption(${i})">${o}</li>`;});h+=`</ul><div class="explanation" id="explanation">${q.explanation}</div>`;document.getElementById('question-card').innerHTML=h;}function selectOption(i){if(answered)return;selectedOption=i;document.getElementById('btn-validate').disabled=false;document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.toggle('selected',x===i);});}function validateAnswer(){if(selectedOption===-1||answered)return;answered=true;const q=shuffledQuestions[currentQuestion],c=q.answer,ok=selectedOption===c;if(ok)score++;answers.push({question:q,selected:selectedOption,correct:ok});document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.add('disabled');if(x===c)e.classList.add('correct');if(x===selectedOption&&!ok)e.classList.add('wrong');});document.getElementById('explanation').style.display='block';document.getElementById('btn-validate').style.display='none';if(currentQuestion<shuffledQuestions.length-1)document.getElementById('btn-next').style.display='inline-block';else setTimeout(showResults,800);}function nextQuestion(){currentQuestion++;showQuestion();}function showResults(){stopTimer();document.getElementById('quiz-area').style.display='none';const r=document.getElementById('results');r.style.display='block';const t=shuffledQuestions.length,p=Math.round(score/t*100);let lc,m,d;if(p>=80){lc='level-excellent';m='Excellent !';d='Solide base.';}else if(p>=60){lc='level-good';m='Bon niveau !';d='Revoyez les erreurs.';}else if(p>=40){lc='level-average';m='Moyen.';d='Travaillez vos points faibles.';}else{lc='level-weak';m='A renforcer.';d='Reprenez les bases.';}const cats=['HTML','CSS','JavaScript','PHP','MySQL'];const cs={};cats.forEach(c=>cs[c]={total:0,correct:0});answers.forEach(a=>{cs[a.question.category].total++;if(a.correct)cs[a.question.category].correct++;});let ch='<div class="cat-scores">';cats.forEach(c=>{const s=cs[c],pc=s.total>0?Math.round(s.correct/s.total*100):0;let co='#e74c3c';if(pc>=80)co='#27ae60';else if(pc>=60)co='#2980b9';else if(pc>=40)co='#f39c12';ch+=`<div class="cat-score-card"><div class="cat-name"><span class="category-badge cat-${c.toLowerCase()}">${c}</span></div><div class="cat-pct" style="color:${co}">${pc}%</div><div class="cat-detail">${s.correct}/${s.total}</div></div>`;});ch+='</div>';r.innerHTML=`<div class="score-circle ${lc}">${p}%<span class="label">${score}/${t}</span></div><div class="level-message">${m}</div><div class="level-detail">${d}</div>${ch}<div class="btn-container" style="margin-top:30px"><button class="btn btn-primary" onclick="startQuiz()">Recommencer</button><button class="btn btn-restart" onclick="retryFailed()" style="margin-left:10px">Retravailler mes erreurs</button><button class="btn btn-restart" onclick="location.href='/dashboard'" style="margin-left:10px">Accueil</button></div>`;fetch('/api/scores',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content},body:JSON.stringify({qcm_name:'qcm12',score,total:t,percentage:p,duration_seconds:timerSeconds})});}function retryFailed(){const f=answers.filter(a=>!a.correct);if(!f.length){alert('Aucune erreur !');return;}shuffledQuestions=f.map(x=>({...x.question}));currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}
</script>
